changes.original_css:
/* Button Styles */

.btn-primary {
  background-color: #2563eb;
  color: #ffffff;
  padding: 12px 24px;
  border-radius: 6px;
  font-size: 14px;
  font-weight: 600;
  border: 1px solid #1d4ed8;
  box-shadow:
    0 1px 3px 0 rgba(0, 0, 0, 0.1),
    0 1px 2px 0 rgba(0, 0, 0, 0.06);
}

.btn-primary:hover {
  background-color: #1d4ed8;
}

.btn-secondary {
  background-color: #7c3aed;
  color: #f9fafb;
  padding: 8px 16px;
  border-radius: 4px;
  font-size: 14px;
  font-weight: 500;
}

.btn-danger {
  background-color: #ef4444;
  color: #ffffff;
  padding: 12px 24px;
  border-radius: 6px;
  font-size: 16px;
  font-weight: 600;
  border: 2px solid #dc2626;
}

.btn-success {
  background-color: #10b981;
  color: white;
  padding: 0.75rem 1.5rem;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

.btn-small {
  padding: 4px 8px;
  font-size: 12px;
  border-radius: 2px;
}

.btn-large {
  padding: 16px 32px;
  font-size: 18px;
  border-radius: 8px;
}

